export function nextGeneration(liveCells: Array<[number, number]>): Array<[number, number]> {
  if (liveCells.length === 0) {
    return [];
  }

  // Count neighbors for each live cell
  const result: Array<[number, number]> = [];

  for (const [x, y] of liveCells) {
    let neighbors = 0;

    // Count live neighbors
    for (const [ox, oy] of liveCells) {
      if (ox === x && oy === y) continue; // Skip self
      const dx = Math.abs(ox - x);
      const dy = Math.abs(oy - y);
      if (dx <= 1 && dy <= 1) {
        neighbors++;
      }
    }

    // Survival rule: live cell with 2 or 3 neighbors survives
    if (neighbors === 2 || neighbors === 3) {
      result.push([x, y]);
    }
  }

  return result;
}

